import { Pickaxe, Zap, ChevronRight, Wallet, Users, LayoutDashboard, Calendar, Info, TrendingUp, Sparkles } from 'lucide-react';

const DailyCheckIn: React.FC = () => {
    const { user, handleCheckIn, canCheckIn } = useContext(UserContext);
    const [message, setMessage] = useState('');
    const rewards = [3, 5, 7, 10, 13, 16, 20];
    const streak = user?.checkInStreak || 0;

    const onCheckInClick = async () => {
        const result = await handleCheckIn();
        if (!result.success) {
            setMessage(result.message);
        }
    };

    return (
        <div className="bg-white dark:bg-brand-gray-900 rounded-3xl p-5 shadow-sm border border-brand-gray-100 dark:border-brand-gray-800">
            <div className="flex justify-between items-center mb-4">
                <h3 className="font-bold text-sm uppercase tracking-wider text-brand-gray-500 dark:text-brand-gray-400 flex items-center gap-2">
                    <Calendar size={16} className="text-brand-purple" /> Daily Streak
                </h3>
                <span className="text-xs font-bold text-brand-purple bg-brand-purple/10 px-2 py-1 rounded-full">
                    Day {streak + 1}
                </span>
            </div>

            <div className="flex justify-between gap-1 mb-5">
                {rewards.map((reward, index) => {
                    const isCompleted = index < (streak % 7);
                    const isCurrent = index === (streak % 7);
                    return (
                        <div key={index} className={`flex-1 flex flex-col items-center p-2 rounded-xl border transition-all duration-300 ${
                            isCurrent 
                            ? 'bg-brand-purple border-brand-purple text-white shadow-lg shadow-brand-purple/30' 
                            : isCompleted 
                                ? 'bg-green-500/10 border-green-500/30 text-green-500' 
                                : 'bg-brand-gray-50 dark:bg-brand-gray-800 border-transparent text-brand-gray-400'
                        }`}>
                            <span className="text-[10px] font-bold opacity-70 mb-1">{index + 1}</span>
                            <span className="text-sm font-black">{reward}</span>
                        </div>
                    );
                })}
            </div>

            <button
                onClick={onCheckInClick}
                disabled={!canCheckIn()}
                className="w-full py-3 font-bold text-white bg-brand-purple rounded-2xl hover:bg-brand-purple-dark disabled:bg-brand-gray-200 dark:disabled:bg-brand-gray-800 dark:disabled:text-brand-gray-600 disabled:shadow-none shadow-md shadow-brand-purple/20 transition-all active:scale-95"
            >
                {canCheckIn() ? `Collect Day ${streak + 1} Reward` : 'Streak Maintained'}
            </button>
        </div>
    );
};

