const HomePageLogo = ({ className }: { className?: string }) => (
    <img src="https://raw.githubusercontent.com/rashidali347/trsustrium001-logo/refs/heads/main/logo.png" alt="Trustrium Logo" className={className} />
);

const HomePage: React.FC = () => {
    const { user, trustBalance, tsrBalance, isMining, miningEndTime, totalMiningRate, baseMiningRate, referralMiningRate, startMining } = useContext(UserContext);

    const [timeRemaining, setTimeRemaining] = useState(0);
    const [rateIncreased, setRateIncreased] = useState(false);
    const [isBonusOpen, setIsBonusOpen] = useState(false);
    const prevRateRef = useRef(totalMiningRate);

    const progress = miningEndTime ? Math.max(0, ((24 * 3600000 - timeRemaining) / (24 * 3600000)) * 100) : 0;

    useEffect(() => {
        if (totalMiningRate > prevRateRef.current) {
            setRateIncreased(true);
            const timer = setTimeout(() => setRateIncreased(false), 800);
            return () => clearTimeout(timer);
        }
        prevRateRef.current = totalMiningRate;
    }, [totalMiningRate]);

    useEffect(() => {
        if (!isMining || !miningEndTime) {
            setTimeRemaining(0);
            return;
        }
        const interval = setInterval(() => {
            const remaining = Math.max(0, miningEndTime - Date.now());
            setTimeRemaining(remaining);
        }, 1000);
        return () => clearInterval(interval);
    }, [isMining, miningEndTime]);

    const hours = Math.floor(timeRemaining / 3600000);
    const minutes = Math.floor((timeRemaining % 3600000) / 60000);
    const seconds = Math.floor((timeRemaining % 60000) / 1000);

    return (
        <div className="container mx-auto max-w-lg px-6 pb-28 pt-4 space-y-6 flex flex-col min-h-screen font-sans">
            <DailyCheckInModal isOpen={isBonusOpen} onClose={() => setIsBonusOpen(false)} />

            {/* Header: User & Daily Bonus Trigger */}
            <div className="flex items-center justify-between py-2">
                <div className="flex items-center gap-3">
                    <img src={user?.avatar || `https://i.pravatar.cc/100?u=${user?.id}`} className="w-10 h-10 rounded-full border-2 border-brand-purple/20" alt="Avatar" />
                    <div>
                        <p className="text-xs text-brand-gray-500 font-medium">Hello,</p>
                        <p className="text-sm font-bold text-brand-gray-900 dark:text-white">@{user?.username}</p>
                    </div>
                </div>
                <button 
                    onClick={() => setIsBonusOpen(true)}
                    className="p-3 bg-white dark:bg-brand-gray-900 rounded-2xl shadow-sm border border-brand-gray-100 dark:border-brand-gray-800 text-brand-purple relative"
                >
                    <Calendar size={22} />
                    {user?.lastCheckIn && (new Date().setHours(0,0,0,0) > new Date(user.lastCheckIn).setHours(0,0,0,0)) && (
                        <span className="absolute top-2 right-2 w-3 h-3 bg-red-500 rounded-full border-2 border-white dark:border-brand-gray-950 animate-pulse"></span>
                    )}
                </button>
            </div>

            {/* Clean Balance Display */}
            <div className="text-center py-4 relative overflow-hidden bg-brand-purple/5 rounded-[2rem] border border-brand-purple/10">
                <p className="text-xs font-bold text-brand-purple uppercase tracking-[0.2em] mb-2">Total Trust Pool</p>
                <div className="flex items-baseline justify-center gap-2">
                    <h2 className="text-6xl font-bold tracking-tighter text-brand-gray-900 dark:text-white tabular-nums">
                        {trustBalance.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                    </h2>
                </div>
                <div className="mt-2 flex items-center justify-center gap-2 text-brand-gray-400 text-xs font-medium">
                    <span>≈ {tsrBalance.toFixed(4)} $TSR</span>
                </div>
            </div>

            {/* Mining Status Card - Reference Style */}
            <div className="bg-white dark:bg-brand-gray-900 rounded-[2.5rem] p-8 shadow-xl border border-brand-gray-50 dark:border-brand-gray-800">
                <div className="flex justify-between items-center mb-10">
                    <h3 className="text-2xl font-bold text-brand-gray-900 dark:text-white">Mining Status</h3>
                    <div className="flex items-center gap-2">
                        <div className={`w-2 h-2 rounded-full ${isMining ? 'bg-green-500 animate-pulse' : 'bg-brand-gray-300'}`} />
                        <span className={`text-sm font-bold uppercase tracking-wide ${isMining ? 'text-green-500' : 'text-brand-gray-400'}`}>
                            {isMining ? 'Active' : 'Inactive'}
                        </span>
                    </div>
                </div>

                <div className="flex flex-col items-center text-center mb-8">
                    <div className="flex items-baseline gap-2 mb-2">
                        <span className="text-5xl font-bold text-brand-purple tabular-nums">{totalMiningRate.toFixed(4)}</span>
                        <span className="text-2xl font-bold text-brand-gray-400">Trust/h</span>
                    </div>
                    <p className="text-sm font-bold text-brand-gray-900 dark:text-white mb-6">Total mining rate:</p>

                    {!isMining ? (
                        <button 
                            onClick={startMining}
                            className="text-lg font-bold text-brand-purple hover:underline transition-all flex items-center gap-2 group"
                        >
                            Start mining <ChevronRight size={20} className="group-hover:translate-x-1 transition-transform" />
                        </button>
                    ) : (
                        <div className="space-y-2">
                            <p className="text-2xl font-mono font-bold text-brand-gray-700 dark:text-brand-gray-300 tracking-[0.2em]">
                                {String(hours).padStart(2, '0')}:{String(minutes).padStart(2, '0')}:{String(seconds).padStart(2, '0')}
                            </p>
                            <div className="w-48 h-1.5 bg-brand-gray-100 dark:bg-brand-gray-800 rounded-full overflow-hidden">
                                <div className="h-full bg-brand-purple transition-all duration-1000 ease-linear" style={{ width: `${progress}%` }}></div>
                            </div>
