                            <Info size={16} className="text-brand-gray-400" />
                        </div>
                        <span className="text-sm font-bold text-brand-gray-700 dark:text-brand-gray-300 tabular-nums">{baseMiningRate.toFixed(4)} Trust/h</span>
                    </div>
                    <div className="flex justify-between items-center">
                        <div className="flex items-center gap-2">
                            <span className="text-sm font-bold text-brand-gray-900 dark:text-white">Team Boost</span>
                            <Info size={16} className="text-brand-gray-400" />
                        </div>
                        <span className="text-sm font-bold text-brand-gray-700 dark:text-brand-gray-300 tabular-nums">{referralMiningRate.toFixed(4)} Trust/h</span>
                    </div>
                    <div className="flex justify-between items-center">
                        <div className="flex items-center gap-2">
                            <span className="text-sm font-bold text-brand-gray-900 dark:text-white">Streak bonus</span>
                            <Info size={16} className="text-brand-gray-400" />
                        </div>
                        <span className="text-sm font-bold text-brand-gray-700 dark:text-brand-gray-300 tabular-nums">0 Trust/h</span>
                    </div>
                </div>
            </div>

            {/* Quick Actions */}
            <div className="grid grid-cols-3 gap-4">
                <ReactRouterDOM.Link to="/wallet" className="flex flex-col items-center justify-center p-5 bg-white dark:bg-brand-gray-900 rounded-[2rem] shadow-sm border border-brand-gray-50 dark:border-brand-gray-800 transition-all active:scale-95">
                    <div className="w-12 h-12 rounded-2xl bg-brand-purple/10 flex items-center justify-center text-brand-purple mb-3">
                        <Wallet size={20} />
                    </div>
                    <span className="text-[10px] font-bold uppercase tracking-widest text-brand-gray-500">Wallet</span>
                </ReactRouterDOM.Link>
                <ReactRouterDOM.Link to="/referrals" className="flex flex-col items-center justify-center p-5 bg-white dark:bg-brand-gray-900 rounded-[2rem] shadow-sm border border-brand-gray-50 dark:border-brand-gray-800 transition-all active:scale-95">
                    <div className="w-12 h-12 rounded-2xl bg-brand-purple/10 flex items-center justify-center text-brand-purple mb-3">
                        <Users size={20} />
                    </div>
                    <span className="text-[10px] font-bold uppercase tracking-widest text-brand-gray-500">Nodes</span>
                </ReactRouterDOM.Link>
                <ReactRouterDOM.Link to="/mine" className="flex flex-col items-center justify-center p-5 bg-white dark:bg-brand-gray-900 rounded-[2rem] shadow-sm border border-brand-gray-50 dark:border-brand-gray-800 transition-all active:scale-95">
