                    <span className="text-[10px] font-bold uppercase tracking-widest text-brand-gray-500">Stats</span>
                </ReactRouterDOM.Link>
            </div>

            {/* Global Stats Link */}
            <ReactRouterDOM.Link to="/explore" className="flex items-center justify-between p-6 bg-brand-gray-950 text-white rounded-[2.5rem] hover:bg-black transition-all group">
