                </div>

                <div className="grid grid-cols-4 gap-2 mb-8">
                    {rewards.map((reward, index) => {
                        const isCompleted = index < (streak % 7);
                        const isCurrent = index === (streak % 7);
                        return (
                            <div key={index} className={`flex flex-col items-center py-4 rounded-2xl border transition-all duration-500 ${
                                isCurrent 
                                ? 'bg-brand-purple border-brand-purple text-white shadow-lg scale-105 z-10' 
