                            }`}>
                                <span className="text-[10px] font-bold opacity-50 mb-1">{index + 1}</span>
                                <span className="text-sm font-bold">{reward}</span>
                            </div>
                        );
                    })}
                </div>

                <button
                    onClick={async () => {
                        await handleCheckIn();
                        onClose();
                    }}
                    disabled={!canCheckIn()}
                    className="w-full py-4 font-bold uppercase tracking-[0.1em] text-sm text-white bg-brand-purple rounded-2xl hover:brightness-110 disabled:bg-brand-gray-100 dark:disabled:bg-brand-gray-800 dark:disabled:text-brand-gray-600 shadow-xl shadow-brand-purple/20 transition-all active:scale-[0.98]"
                >
                    {canCheckIn() ? `Claim Reward` : 'Next in 24h'}
                </button>
            </div>
        </div>
    );
};

