const ZigzagProgress: React.FC<{ progress: number }> = ({ progress }) => {
    // Generate a zigzag path
    const width = 100;
    const height = 10;
    const points = 10;
    const step = width / points;
    let path = `M 0 ${height / 2}`;
    for (let i = 1; i <= points; i++) {
        const x = i * step;
        const y = i % 2 === 0 ? height : 0;
        path += ` L ${x} ${y}`;
    }

    return (
        <div className="relative w-full h-4 mt-2">
            <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-full overflow-visible" preserveAspectRatio="none">
                {/* Background Zigzag */}
                <path d={path} fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-brand-gray-200 dark:text-brand-gray-800" />
                {/* Progress Zigzag */}
                <path 
                    d={path} 
                    fill="none" 
                    stroke="#5839FF" 
                    strokeWidth="2.5" 
                    strokeLinecap="round" 
                    strokeLinejoin="round" 
                    strokeDasharray={width * 2}
                    strokeDashoffset={width * 2 * (1 - progress / 100)}
                    className="transition-all duration-1000 ease-out"
                />
            </svg>
        </div>
    );
};

