const ZigzagProgress: React.FC<{ progress: number; variant?: 'gold' | 'default' }> = ({ progress, variant = 'default' }) => {
    const width = 100;
    const height = 10;
    const points = 10;
    const step = width / points;
    let path = `M 0 ${height / 2}`;
    for (let i = 1; i <= points; i++) {
        const x = i * step;
        const y = i % 2 === 0 ? height : 0;
        path += ` L ${x} ${y}`;
    }

    const baseColor = variant === 'gold' ? 'rgba(0,0,0,0.1)' : 'currentColor';
    const progressColor = variant === 'gold' ? '#FFFFFF' : '#5839FF';

    return (
        <div className="relative w-full h-4 mt-2">
            <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-full overflow-visible" preserveAspectRatio="none">
                <path d={path} fill="none" stroke={baseColor} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={variant === 'default' ? 'text-brand-gray-200 dark:text-brand-gray-800' : ''} />
                <path 
                    d={path} 
                    fill="none" 
                    stroke={progressColor} 
                    strokeWidth="2.5" 
                    strokeLinecap="round" 
                    strokeLinejoin="round" 
                    strokeDasharray={width * 2}
                    strokeDashoffset={width * 2 * (1 - progress / 100)}
                    className="transition-all duration-1000 ease-out shadow-sm"
                />
            </svg>
        </div>
    );
};

