import ToastContainer from './components/ui/ToastContainer'; 
import SplashScreen from './components/layout/SplashScreen'; 

const App: React.FC = () => {
  const { theme } = useContext(AppContext);

  React.useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  useEffect(() => {
    // Capture referral code from URL search params (standard URL)
    const searchParams = new URLSearchParams(window.location.search);
    let refCode = searchParams.get('ref');

    // Fallback: Capture referral code from URL hash (HashRouter style)
    if (!refCode) {
        const hash = window.location.hash;
        if (hash.includes('?')) {
             const urlParams = new URLSearchParams(hash.split('?')[1]);
             refCode = urlParams.get('ref');
        }
    }

    if (refCode) {
      sessionStorage.setItem('trustrium-referral-code', refCode);
    }
  }, []);

  return (
    <UserProvider>
      <AppContent />
    </UserProvider>
  );
};

const AppContent: React.FC = () => {
  const { user, firebaseAuthUser, isAuthLoading } = useContext(UserContext); 

  if (isAuthLoading) {
    return <SplashScreen />; 
  }

  // If user document exists (meaning they are logged in and signed up in Firestore)
  // But their email is NOT verified, show the pending page.
  // IMPORTANT: We check user existence first to allow AuthPage to render for logged-out users.
  if (user && firebaseAuthUser && !firebaseAuthUser.emailVerified) {
      return <VerificationPendingPage />;
  }

  return (
    <div className="min-h-screen font-sans text-brand-gray-800 dark:text-brand-gray-200">
      {/* Fix: Use named components directly from react-router-dom */}
      <Routes>
        {!user ? (
          <>
            <Route path="/auth" element={<AuthPage />} />
            <Route path="*" element={<Navigate to="/auth" />} />
          </>
        ) : (
          <Route element={<MainLayout />}>
            <Route path="/" element={<HomePage />} />
            <Route path="/mine" element={<MinePage />} />
            <Route path="/wallet" element={<WalletPage />} />
            <Route path="/explore" element={<ExplorePage />} />
            <Route path="/referrals" element={<ReferralPage />} />
            <Route path="/profile" element={<ProfilePage />} />
            <Route path="/settings/:page" element={<SettingsPage />} />
            {/* /kyc route removed or redirected to ensure use of external app */}
            <Route path="/kyc" element={<KycPage />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Route>
        )}
      </Routes>
      <ToastContainer />
    </div>
  );
};

