import React, { useContext, useState } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { UserContext } from '../contexts/UserContext';
import { AppContext } from '../contexts/AppContext';
import { User as UserIcon, Bell, Lock, ChevronLeft, ChevronRight, Key, Loader2, Mail, ShieldCheck, Eye, EyeOff, Globe2, Phone, Save, LogOut } from 'lucide-react';
import { COUNTRIES } from '../lib/countries';

const ChangePasswordModal: React.FC<{ onClose: () => void }> = ({ onClose }) => {
    const { changePassword } = useContext(UserContext);
    const { showSuccessToast, showErrorToast } = useContext(AppContext);
    const [currentPassword, setCurrentPassword] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [error, setError] = useState('');
    const [isLoading, setIsLoading] = useState(false);

    const handleSubmit = async () => {
        setError('');
        if (newPassword !== confirmPassword) {
            setError("New passwords do not match.");
            return;
        }
        if (newPassword.length < 6) {
            setError("Password must be at least 6 characters long.");
            return;
        }

        setIsLoading(true);
        const result = await changePassword(currentPassword, newPassword);
        setIsLoading(false);

        if (result === 'SUCCESS') {
            showSuccessToast("Password updated successfully!");
            onClose();
        } else if (result === 'INVALID_PASSWORD') {
            setError("Incorrect current password.");
        } else if (result === 'REAUTH_REQUIRED') {
            setError("Re-authentication required. Please login again.");
        } else {
            setError("Update failed. Please try again.");
        }
    };

    return (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-[110] p-4">
            <div className="bg-white dark:bg-brand-gray-900 rounded-3xl p-8 w-full max-w-md shadow-2xl border border-brand-gray-100 dark:border-brand-gray-800">
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-2xl font-bold">Security Update</h2>
                    <button onClick={onClose} className="p-2 hover:bg-brand-gray-100 dark:hover:bg-brand-gray-800 rounded-full transition-colors"><X size={24}/></button>
                </div>
                <div className="space-y-4">
                    <div>
                        <label className="text-xs font-bold text-brand-gray-500 uppercase ml-1">Current Password</label>
                        <input type="password" value={currentPassword} onChange={e => setCurrentPassword(e.target.value)} className="w-full p-4 mt-1 bg-brand-gray-50 dark:bg-brand-gray-800 border-none rounded-2xl focus:ring-2 focus:ring-brand-purple focus:outline-none"/>
                    </div>
                    <div>
                        <label className="text-xs font-bold text-brand-gray-500 uppercase ml-1">New Password</label>
                        <input type="password" value={newPassword} onChange={e => setNewPassword(e.target.value)} className="w-full p-4 mt-1 bg-brand-gray-50 dark:bg-brand-gray-800 border-none rounded-2xl focus:ring-2 focus:ring-brand-purple focus:outline-none"/>
                    </div>
                    <div>
                        <label className="text-xs font-bold text-brand-gray-500 uppercase ml-1">Confirm New Password</label>
                        <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} className="w-full p-4 mt-1 bg-brand-gray-50 dark:bg-brand-gray-800 border-none rounded-2xl focus:ring-2 focus:ring-brand-purple focus:outline-none"/>
                    </div>
                    {error && <p className="text-sm text-red-500 font-medium px-2">{error}</p>}
                </div>
                <div className="flex gap-3 mt-8">
                    <button onClick={onClose} className="flex-1 py-4 font-bold rounded-2xl bg-brand-gray-100 dark:bg-brand-gray-800 text-brand-gray-600 dark:text-brand-gray-300">Cancel</button>
                    <button onClick={handleSubmit} disabled={isLoading} className="flex-2 px-8 py-4 font-bold text-white bg-brand-purple rounded-2xl hover:bg-brand-purple-dark flex items-center justify-center gap-2 disabled:opacity-50">
                        {isLoading ? <Loader2 size={20} className="animate-spin"/> : <Lock size={20}/>}
                        Update
                    </button>
                </div>
            </div>
        </div>
    )
}

