const MINING_TIERS: MiningTier[] = [
    { tier: 1, name: 'Novice', sessionsRequired: 0, bonus: 0.00 },
    { tier: 2, name: 'Apprentice', sessionsRequired: 10, bonus: 0.25 },
    { tier: 3, name: 'Journeyman', sessionsRequired: 30, bonus: 0.50 },
