import React, { useState, useEffect, useContext } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { UserContext } from '../contexts/UserContext';
import { AppContext } from '../contexts/AppContext';
import { ListTodo, Terminal, ShieldCheck, ShieldAlert, Clock, ArrowRight, Loader2, Info, Activity, Database } from 'lucide-react';
import { RewardAnimation } from '../components/ui/RewardAnimation';

interface SystemChallenge {
    question: string;
    options: string[];
    correctIndex: number;
}

const DailyTaskPage: React.FC = () => {
    const { user, submitAiTask } = useContext(UserContext); // Keeping logic names for stability
    const { showSuccessToast, showErrorToast } = useContext(AppContext);

    const [loading, setLoading] = useState(true);
    const [challenge, setChallenge] = useState<SystemChallenge | null>(null);
    const [selectedIndex, setSelectedIndex] = useState<number | null>(null);
    const [submitting, setSubmitting] = useState(false);
    const [showReward, setShowReward] = useState(false);
    const [timeLeft, setTimeLeft] = useState("");

    const today = new Date().toISOString().split('T')[0];
    const isAttemptedToday = user?.lastAiTaskDate === today;

    useEffect(() => {
        if (!isAttemptedToday) {
            generateSystemChallenge();
        } else {
            calculateTimeUntilNext();
            setLoading(false);
        }
    }, [isAttemptedToday]);

    const calculateTimeUntilNext = () => {
        const now = new Date();
        const next = new Date();
        next.setHours(24, 0, 0, 0);
        const diff = next.getTime() - now.getTime();
        const hours = Math.floor(diff / (1000 * 60 * 60));
        const mins = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
        setTimeLeft(`${hours}h ${mins}m`);
    };

    const generateSystemChallenge = async () => {
        setLoading(true);
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: 'Act as a secure protocol validation system for Trustrium. Generate a multiple-choice technical question about Web3, Blockchain, or the Trustrium network (www.trustrium.com). DO NOT use words like "AI", "Assistant", "Robot", or "Generated". The question should sound like a professional system check. Provide 4 options and the correct index in JSON format.',
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            question: { type: Type.STRING },
                            options: { 
                                type: Type.ARRAY, 
                                items: { type: Type.STRING },
                                minItems: 4,
                                maxItems: 4
                            },
                            correctIndex: { type: Type.INTEGER }
                        },
                        required: ["question", "options", "correctIndex"]
                    }
                }
            });

            if (response.text) {
                setChallenge(JSON.parse(response.text));
            }
        } catch (error) {
            console.error("System Error:", error);
            // Professional fallback
            setChallenge({
                question: "Which mechanism ensures the security of the Trustrium decentralized human ledger?",
                options: ["Proof of Stake", "Human Protocol Consensus", "Proof of Work", "Centralized Auth"],
                correctIndex: 1
            });
        } finally {
            setLoading(false);
        }
    };

    const handleChoice = (index: number) => {
        if (submitting || isAttemptedToday) return;
        setSelectedIndex(index);
    };

    const handleSubmit = async () => {
        if (selectedIndex === null || !challenge || submitting) return;

        setSubmitting(true);
        const isCorrect = selectedIndex === challenge.correctIndex;

        await submitAiTask(isCorrect);

        if (isCorrect) {
            setShowReward(true);
            showSuccessToast("Protocol Signature: Validated. Reward Credited.");
        } else {
            showErrorToast("Validation Failed. Access denied for 24h.");
        }
        setSubmitting(false);
    };

    if (loading) {
        return (
            <div className="container mx-auto max-w-lg p-8 flex flex-col items-center justify-center min-h-[60vh] text-center space-y-4">
                <div className="relative">
                    <div className="w-24 h-24 rounded-full border-4 border-[#5839FF]/10 border-t-[#5839FF] animate-spin"></div>
                    <Terminal size={32} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-[#5839FF] animate-pulse" />
                </div>
                <h2 className="text-xl font-black text-brand-gray-900 dark:text-white uppercase tracking-widest">Accessing Protocol</h2>
                <p className="text-sm text-brand-gray-500 animate-pulse font-mono">Verifying Node Status...</p>
            </div>
        );
    }

    if (isAttemptedToday) {
        return (
            <div className="container mx-auto max-w-lg p-6 space-y-6">
                <div className="bg-white dark:bg-brand-gray-900 rounded-[2.5rem] p-8 border border-brand-gray-100 dark:border-brand-gray-800 text-center shadow-2xl relative overflow-hidden">
                    <div className={`mx-auto w-20 h-20 rounded-full flex items-center justify-center mb-6 ${user?.aiTaskCorrect ? 'bg-green-500/10 text-green-500' : 'bg-red-500/10 text-red-500'}`}>
                        {user?.aiTaskCorrect ? <ShieldCheck size={48} /> : <ShieldAlert size={48} />}
                    </div>
                    <h2 className="text-2xl font-black text-brand-gray-900 dark:text-white uppercase tracking-tight">
                        {user?.aiTaskCorrect ? 'Validation Complete' : 'System Locked'}
                    </h2>
                    <p className="text-brand-gray-500 mt-2 text-sm leading-relaxed max-w-xs mx-auto">
                        {user?.aiTaskCorrect 
                            ? "Your daily validation signature has been recorded. Next protocol challenge available in 24 hours."
                            : "Your validation signature was rejected by the network. Entry is restricted until the next cycle."}
                    </p>

                    <div className="mt-8 pt-8 border-t border-brand-gray-100 dark:border-brand-gray-800">
                        <div className="flex items-center justify-center gap-2 text-[#5839FF]">
                            <Clock size={18} />
                            <span className="font-black text-sm uppercase tracking-widest">Next Validation: {timeLeft}</span>
                        </div>
                    </div>
                </div>

                <div className="bg-brand-gray-50 dark:bg-brand-gray-950 p-6 rounded-[2rem] border border-dashed border-brand-gray-200 dark:border-brand-gray-800">
                    <div className="flex items-start gap-4">
                        <div className="p-2 bg-[#5839FF]/10 text-[#5839FF] rounded-lg">
                            <Database size={20} />
                        </div>
                        <div>
                            <h4 className="text-sm font-bold text-brand-gray-900 dark:text-white uppercase tracking-tighter">Node Integrity</h4>
                            <p className="text-xs text-brand-gray-500 mt-1">Challenge tasks are automated protocol steps to verify human activity and maintain decentralization within the Trustrium ledger.</p>
                        </div>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="container mx-auto max-w-lg p-6 space-y-6 pb-32">
            {showReward && <RewardAnimation amount={0.5} unit="Trust" onAnimationEnd={() => setShowReward(false)} />}

            <header className="space-y-1">
                <div className="flex items-center gap-2 text-[#5839FF]">
                    <Activity size={20} className="animate-pulse" />
                    <span className="text-[10px] font-black uppercase tracking-[0.3em]">System Task</span>
                </div>
                <h1 className="text-4xl font-bold text-brand-gray-900 dark:text-white tracking-tight">Protocol Check</h1>
                <p className="text-brand-gray-500 text-sm">Verify your node status to claim 0.5 Trust.</p>
            </header>

            <div className="bg-white dark:bg-brand-gray-900 rounded-[3rem] p-8 border border-brand-gray-100 dark:border-brand-gray-800 shadow-2xl space-y-8 relative overflow-hidden">
                <div className="absolute top-0 right-0 p-8 opacity-5">
                    <Terminal size={120} />
                </div>

                <div className="relative z-10">
                    <div className="bg-[#5839FF]/5 p-6 rounded-[2rem] border border-[#5839FF]/10">
                        <p className="text-lg font-bold text-brand-gray-800 dark:text-white leading-relaxed font-mono">
                            {challenge?.question}
                        </p>
                    </div>
                </div>

                <div className="grid gap-3 relative z-10">
                    {challenge?.options.map((opt, i) => (
                        <button
                            key={i}
                            onClick={() => handleChoice(i)}
                            className={`w-full p-5 text-left rounded-[1.5rem] font-bold text-sm transition-all flex items-center justify-between group active:scale-98 ${
                                selectedIndex === i 
                                ? 'bg-[#5839FF] text-white shadow-xl shadow-[#5839FF]/20 translate-x-2' 
                                : 'bg-brand-gray-50 dark:bg-brand-gray-950 text-brand-gray-600 dark:text-brand-gray-300 hover:bg-brand-gray-100 dark:hover:bg-brand-gray-800'
                            }`}
                        >
                            <span className="flex-1">{opt}</span>
                            <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-colors ${selectedIndex === i ? 'border-white/40 bg-white/20' : 'border-brand-gray-200 dark:border-brand-gray-700'}`}>
                                {selectedIndex === i && <div className="w-2 h-2 rounded-full bg-white animate-scale-in" />}
                            </div>
                        </button>
                    ))}
                </div>

                <button
                    onClick={handleSubmit}
                    disabled={selectedIndex === null || submitting}
                    className={`w-full py-5 rounded-[2rem] font-black text-lg tracking-widest transition-all flex items-center justify-center gap-3 shadow-2xl relative overflow-hidden group ${selectedIndex === null || submitting ? 'bg-brand-gray-100 dark:bg-brand-gray-800 text-brand-gray-400' : 'bg-[#5839FF] text-white active:scale-95 shadow-[#5839FF]/30'}`}
                >
                    {submitting ? (
                        <Loader2 className="animate-spin" size={24} />
                    ) : (
                        <>
                            <span>VALIDATE SIGNATURE</span>
                            <ArrowRight size={22} className="group-hover:translate-x-1 transition-transform" />
                        </>
                    )}
                </button>
            </div>

            <p className="text-center text-[10px] font-black text-brand-gray-400 uppercase tracking-widest px-8 leading-relaxed opacity-60 font-mono">
                System Log: Challenge ID-{Math.floor(Math.random()*99999)}. User verification required for daily node syncing.
            </p>
        </div>
    );
};

