                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            question: { type: Type.STRING },
                            options: { 
                                type: Type.ARRAY, 
                                items: { type: Type.STRING },
                                minItems: 4,
                                maxItems: 4
                            },
                            correctIndex: { type: Type.INTEGER }
                        },
                        required: ["question", "options", "correctIndex"]
                    }
                }
            });

            if (response.text) {
                setChallenge(JSON.parse(response.text));
            }
        } catch (error) {
            console.error("System Error:", error);
            setChallenge({
                question: "What is the primary token used in the Trustrium network for utility?",
                options: ["Bitcoin", "TSR Token", "Ethereum", "Solana"],
                correctIndex: 1
            });
        } finally {
            setLoading(false);
        }
