        avatar: `https://i.pravatar.cc/40?u=${username}`,
        kycStatus: KycStatus.NotSubmitted,
        miningStatus: Math.random() > 0.3 ? 'active' : 'inactive',
    };

    const newTx: Transaction = {
        id: `tx_${generateRandomHex(10)}`,
        trxId: `TSR-TX-${generateRandomHex(24).toUpperCase()}`,
        date: new Date().toISOString(),
        type: 'referral',
        amountTrust: 5,
        amountTSR: 0,
        to: `Referral: @${username}`,
        status: 'pending',
    };

    updateUser({
        referralTeam: [...user.referralTeam, newReferral],
        referrals: user.referralTeam.length + 1,
        transactions: [newTx, ...user.transactions],
    });
  };

 const verifyReferral = (referralId: string) => {
    if (!user) return;
    const refToUpdate = user.referralTeam.find(ref => ref.id === referralId);
    if (!refToUpdate || refToUpdate.kycStatus === KycStatus.Approved) return;

    const updatedReferralTeam = user.referralTeam.map(ref =>
      ref.id === referralId ? { ...ref, kycStatus: KycStatus.Approved } : ref
    );

    let txUpdated = false;
    const newTxs = user.transactions.map(tx => {
      if (!txUpdated && tx.type === 'referral' && tx.status === 'pending' && tx.to === `Referral: @${refToUpdate.username}`) {
        txUpdated = true;
        return { ...tx, status: 'completed' as const };
      }
      return tx;
    });

    const reward = 5;
    const updatePayload: Partial<User> = {
        referralTeam: updatedReferralTeam,
        trustBalance: user.trustBalance + reward,
        totalTrustEarned: (user.totalTrustEarned || 0) + reward,
        transactions: newTxs,
    };

    if (isMining && user.miningSessionStartBalance !== undefined && user.miningSessionStartBalance !== null) {
        updatePayload.miningSessionStartBalance = user.miningSessionStartBalance + reward;
    }

    updateUser(updatePayload);
  };

  const startMining = () => {
    if (user && !isMining) {
      const endTime = Date.now() + 24 * 60 * 60 * 1000;
      updateUser({ 
        miningEndTime: endTime,
        miningSessionStartBalance: user.trustBalance,
        currentMiningRate: totalMiningRate,
      });
    }
  };

  useEffect(() => {
      let intervalId: ReturnType<typeof setInterval> | undefined;
      if (isMining && user?.miningSessionStartBalance !== undefined && user.miningSessionStartBalance !== null && user.miningEndTime) {
          intervalId = setInterval(() => {
              const now = Date.now();
              if (now >= user.miningEndTime!) {
                  clearInterval(intervalId);
                  return;
              }
              const startTime = user.miningEndTime! - (24 * 60 * 60 * 1000);
              const elapsedMs = now - startTime;
              const rateForSession = user.currentMiningRate ?? totalMiningRate;
              const minedSoFar = (rateForSession / 3600000) * elapsedMs;

              setUser(currentUser => {
                  if (!currentUser || currentUser.miningSessionStartBalance === undefined || currentUser.miningSessionStartBalance === null) return null;
                  return { ...currentUser, trustBalance: currentUser.miningSessionStartBalance + minedSoFar };
              });
          }, 1000);
      }
      return () => { if (intervalId) clearInterval(intervalId); };
  }, [isMining, user?.id, user?.miningEndTime, user?.miningSessionStartBalance, totalMiningRate, user?.currentMiningRate]);

  useEffect(() => {
      if (!user || !isMining || !user.miningEndTime || user.miningSessionStartBalance === undefined || user.miningSessionStartBalance === null) return;
      const timeToFinish = user.miningEndTime - Date.now();
      if (timeToFinish <= 0) return;

      const timer = setTimeout(() => {
        const rateForSession = user.currentMiningRate ?? totalMiningRate;
        const minedAmount = rateForSession * 24;
        const newBalance = user.miningSessionStartBalance! + minedAmount;
        const newSessions = (user.miningSessionsCompleted || 0) + 1;

        const newTierObj = [...MINING_TIERS].reverse().find(t => newSessions >= t.sessionsRequired) || MINING_TIERS[0];
        const newTier = newTierObj.tier;

        const newTx: Transaction = {
            id: `tx_${generateRandomHex(10)}`, trxId: `TSR-TX-${generateRandomHex(24).toUpperCase()}`,
            date: new Date().toISOString(), type: 'mining', amountTSR: 0, amountTrust: minedAmount,
            to: '24h Mining Session', status: 'completed',
            miningRate: rateForSession,
            miningTier: miningTierInfo?.name,
        };
        updateUser({
            trustBalance: newBalance,
            miningSessionsCompleted: newSessions,
            miningTier: newTier,
            miningEndTime: null,
            miningSessionStartBalance: null,
            currentMiningRate: null,
            transactions: [newTx, ...user.transactions],
            totalTrustEarned: (user.totalTrustEarned || 0) + minedAmount,
        });
      }, timeToFinish);

      return () => clearTimeout(timer);
  }, [isMining, user?.id, user?.miningEndTime, user?.miningSessionStartBalance, totalMiningRate, user?.currentMiningRate]);


  const canCheckIn = () => {
        if (!user || !user.lastCheckIn) return true;
        const today = new Date(); today.setHours(0, 0, 0, 0);
        const lastDay = new Date(user.lastCheckIn); lastDay.setHours(0, 0, 0, 0);
        return today > lastDay;
    };

    const handleCheckIn = async (): Promise<{ success: boolean; message: string; reward: number; }> => {
        if (!user || !canCheckIn()) return { success: false, message: "You've already checked in today!", reward: 0 };

        const rewards = [3, 5, 7, 10, 13, 16, 20];
        const currentStreak = user.checkInStreak || 0;
        const newStreakIndex = (currentStreak % 7);
        const reward = rewards[newStreakIndex];

        const newTrustBalance = user.trustBalance + reward;

        const newTx: Transaction = {
            id: `tx_${generateRandomHex(10)}`,
            trxId: `TSR-TX-${generateRandomHex(24).toUpperCase()}`,
            date: new Date().toISOString(),
            type: 'bonus',
            amountTSR: 0,
            amountTrust: reward,
            to: `Daily Check-in Day ${newStreakIndex + 1}`,
            status: 'completed'
        };

        const nextStreak = newStreakIndex + 1;
        const today = new Date();

        const updatePayload: Partial<User> = {
            trustBalance: newTrustBalance,
            transactions: [newTx, ...user.transactions],
            checkInStreak: nextStreak,
            lastCheckIn: today.toISOString(),
            totalTrustEarned: (user.totalTrustEarned || 0) + reward,
        };

        if (isMining && user.miningSessionStartBalance !== undefined && user.miningSessionStartBalance !== null) {
            updatePayload.miningSessionStartBalance = user.miningSessionStartBalance + reward;
        }

        await updateUser(updatePayload);
        return { success: true, message: `Checked in! You earned ${reward} Trust.`, reward };
    };

  const lockWallet = () => setIsWalletLocked(true);
  const unlockWallet = (pin: string): boolean => {
    if (user?.walletPin === pin) {
      setIsWalletLocked(false); setPinAttempts(0); return true;
    } else {
      setPinAttempts(prev => prev + 1); return false;
    }
  };
  const unlockWithPrivateKey = (key: string): boolean => {
    if (user?.privateKey === key) {
      setIsWalletLocked(false); setPinAttempts(0); return true;
    }
    return false;
  };

  const changeWalletPin = (currentPin: string, newPin: string): 'SUCCESS' | 'INVALID_PIN' => {
    if (!user || user.walletPin !== currentPin) return 'INVALID_PIN';
    updateUser({ walletPin: newPin });
    return 'SUCCESS';
  };

  const resetWalletPin = async (password: string, newPin: string): Promise<'SUCCESS' | 'INVALID_PASSWORD' | 'FAILED'> => {
      const firebaseUser = auth.currentUser;
      if (!firebaseUser || !firebaseUser.email) return 'FAILED';

      try {
        const credential = EmailAuthProvider.credential(firebaseUser.email, password);
        await reauthenticateWithCredential(firebaseUser, credential);
        updateUser({ walletPin: newPin });
        return 'SUCCESS';
      } catch (error: any) {
          if (error.code === 'auth/wrong-password' || error.code === 'auth/invalid-credential') return 'INVALID_PASSWORD';
          return 'FAILED';
      }
  };

  const changePassword = async (currentPassword: string, newPassword: string): Promise<'SUCCESS' | 'INVALID_PASSWORD' | 'REAUTH_REQUIRED' | 'FAILED'> => {
      const firebaseUser = auth.currentUser;
      if (!firebaseUser || !firebaseUser.email) return 'FAILED';

      try {
        const credential = EmailAuthProvider.credential(firebaseUser.email, currentPassword);
        await reauthenticateWithCredential(firebaseUser, credential);
        await updatePassword(firebaseUser, newPassword);
        return 'SUCCESS';
      } catch (error: any) {
        if (error.code === 'auth/wrong-password' || error.code === 'auth/invalid-credential') return 'INVALID_PASSWORD';
        if (error.code === 'auth/requires-recent-login') return 'REAUTH_REQUIRED';
        return 'FAILED';
      }
  };

  const reauthenticateUser = async (password: string): Promise<boolean> => {
      const firebaseUser = auth.currentUser;
      if (!firebaseUser || !firebaseUser.email) return false;

      try {
          const credential = EmailAuthProvider.credential(firebaseUser.email, password);
          await reauthenticateWithCredential(firebaseUser, credential);
          return true;
      } catch (error) {
          console.error("Reauthentication failed:", error);
          return false;
      }
  };

    const getMissionsWithProgress = (user: User | null): MissionWithProgress[] => {
        if (!user) return [];
        const verifiedReferrals = user.referralTeam.filter(r => r.kycStatus === KycStatus.Approved).length;

        return MISSIONS.map(mission => {
            const userProgress = (user.missionProgress || []).find(p => p.missionId === mission.id) || { missionId: mission.id, claimed: false };
            const isClaimed = userProgress.claimed;
            let currentProgress = 0;
            let isCompleted = false;

            if (mission.type === 'referral_kyc') {
                currentProgress = verifiedReferrals;
                isCompleted = currentProgress >= mission.goal;
            } else if (mission.type === 'social_share') {
                isCompleted = !isClaimed; 
                currentProgress = isClaimed ? 1 : 0;
            }

            return { ...mission, progress: currentProgress, isCompleted, isClaimed };
        });
    };

    const missions = getMissionsWithProgress(user);

    const claimMissionReward = (missionId: string) => {
        const mission = missions.find(m => m.id === missionId);
        if (!user || !mission || mission.isClaimed || !mission.isCompleted) return;

        let updatedMissionProgress = [...(user.missionProgress || [])];
        const progressIndex = updatedMissionProgress.findIndex(p => p.missionId === missionId);

        if (progressIndex > -1) {
            updatedMissionProgress[progressIndex] = { ...updatedMissionProgress[progressIndex], claimed: true };
        } else {
            updatedMissionProgress.push({ missionId, claimed: true });
        }

        const newTrustBalance = user.trustBalance + mission.reward;
        const newTx: Transaction = {
            id: `tx_${generateRandomHex(10)}`,
            trxId: `TSR-TX-${generateRandomHex(24).toUpperCase()}`,
            date: new Date().toISOString(),
            type: 'bonus',
            amountTSR: 0,
            amountTrust: mission.reward,
            to: `Mission: ${mission.title}`,
            status: 'completed'
        };

        const updatePayload: Partial<User> = {
            trustBalance: newTrustBalance,
            transactions: [newTx, ...user.transactions],
            missionProgress: updatedMissionProgress,
            totalTrustEarned: (user.totalTrustEarned || 0) + mission.reward,
        };

        if (isMining && user.miningSessionStartBalance !== undefined && user.miningSessionStartBalance !== null) {
            updatePayload.miningSessionStartBalance = user.miningSessionStartBalance + mission.reward;
        }

        updateUser(updatePayload);
        addNotification('Reward Claimed!', `You received ${mission.reward} Trust for completing the "${mission.title}" mission.`);
    };

    const totalEarnedTrust = React.useMemo(() => {
        if (!user) return 0;
        let inProgressMining = 0;
        const isCurrentlyMining = !!(user.miningEndTime && user.miningEndTime > Date.now());

        if (isCurrentlyMining && user.miningSessionStartBalance !== undefined && user.miningSessionStartBalance !== null) {
            const startTime = user.miningEndTime! - (24 * 60 * 60 * 1000);
            const elapsedMs = Date.now() - startTime;
            const rateForSession = user.currentMiningRate ?? totalMiningRate;
            inProgressMining = (rateForSession / 3600000) * elapsedMs;
        }
        return (user.totalTrustEarned || 0) + inProgressMining;
    }, [user, isMining, totalMiningRate, user?.currentMiningRate]);

    // Challenge Task
    const submitAiTask = async (correct: boolean) => {
        if (!user) return;

        const today = new Date().toISOString().split('T')[0];
        const updatePayload: Partial<User> = {
            lastAiTaskDate: today,
            aiTaskAttempted: true,
            aiTaskCorrect: correct
        };

        if (correct) {
            const reward = 0.5;
            const newTrust = user.trustBalance + reward;
            const newTotal = (user.totalTrustEarned || 0) + reward;

            const newTx: Transaction = {
                id: `tx_${generateRandomHex(10)}`,
                trxId: `TSR-SYS-${generateRandomHex(24).toUpperCase()}`,
                date: new Date().toISOString(),
                type: 'ai_task',
                amountTSR: 0,
                amountTrust: reward,
                to: 'Daily System Check',
                status: 'completed'
            };

            updatePayload.trustBalance = newTrust;
            updatePayload.totalTrustEarned = newTotal;
            updatePayload.transactions = [newTx, ...user.transactions];

            if (isMining && user.miningSessionStartBalance !== undefined && user.miningSessionStartBalance !== null) {
                updatePayload.miningSessionStartBalance = user.miningSessionStartBalance + reward;
            }
        }

        await updateUser(updatePayload);
    };

    // Social Task
    const submitXFollowTask = async (xUsername: string): Promise<boolean> => {
        if (!user || user.xFollowed) return false;

        const reward = 0.50;
        const newTrust = user.trustBalance + reward;
        const newTotal = (user.totalTrustEarned || 0) + reward;

        const newTx: Transaction = {
            id: `tx_${generateRandomHex(10)}`,
            trxId: `TSR-X-${generateRandomHex(24).toUpperCase()}`,
            date: new Date().toISOString(),
            type: 'social_task',
            amountTSR: 0,
            amountTrust: reward,
            to: `X Follow: @${xUsername}`,
            status: 'completed'
        };

        const updatePayload: Partial<User> = {
            xFollowed: true,
            trustBalance: newTrust,
            totalTrustEarned: newTotal,
            transactions: [newTx, ...user.transactions]
        };

        if (isMining && user.miningSessionStartBalance !== undefined && user.miningSessionStartBalance !== null) {
            updatePayload.miningSessionStartBalance = user.miningSessionStartBalance + reward;
        }

        await updateUser(updatePayload);
        return true;
    };


  return (
    <UserContext.Provider value={{ 
        user, firebaseAuthUser, signup, attemptLogin, logout, updateUser, updateUserSettings, 
        continueWithGoogle, completeGoogleSignup,
        tsrBalance: user?.tsrBalance ?? 0, 
        trustBalance: user?.trustBalance ?? 0,
        unverifiedTrustBalance: user ? user.transactions.filter(tx => tx.type === 'referral' && tx.status === 'pending').reduce((acc, tx) => acc + tx.amountTrust, 0) : 0,
        totalEarnedTrust,
        miningTierInfo, baseMiningRate, referralMiningRate, totalMiningRate, isMining, miningEndTime: user?.miningEndTime ?? null, startMining,
        setKycStatus, addTrust, swapTrustToTSR, 
        transactions: user?.transactions ?? [], addTransaction, sendTsr, 
        submitKyc, 
        notifications: user?.notifications ?? [], markNotificationAsRead, addNotification, clearAllNotifications,
        referrals: user?.referralTeam ?? [], addReferral, verifyReferral, 
        isWalletLocked, pinAttempts, unlockWallet, unlockWithPrivateKey, lockWallet,
        handleCheckIn, canCheckIn,
        leaderboards,
        changeWalletPin, resetWalletPin, changePassword, reauthenticateUser, resetPassword, confirmPasswordResetWithCode, 
        sendVerificationEmail, verifyEmailWithCode, checkEmailVerification,
        missions, claimMissionReward,
        isAuthLoading,
        showVerificationSuccess,
        closeVerificationSuccess,
        emailSystemType: CUSTOM_EMAIL_CONFIG.enabled ? 'code' : 'link',
        submitAiTask,
        submitXFollowTask
    }}>
      {children}
    </UserContext.Provider>
  );
};

import React, { useState, useEffect, useContext } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { UserContext } from '../contexts/UserContext';
import { AppContext } from '../contexts/AppContext';
import { ShieldCheck, ShieldAlert, Clock, ArrowRight, Loader2, Info, CheckCircle2, X as XIcon, Twitter } from 'lucide-react';
import { RewardAnimation } from '../components/ui/RewardAnimation';
import { Link, useNavigate } from 'react-router-dom';

interface SystemChallenge {
    question: string;
    options: string[];
    correctIndex: number;
}

const DailyTaskPage: React.FC = () => {
    const { user, submitAiTask, submitXFollowTask } = useContext(UserContext);
    const { showSuccessToast, showErrorToast } = useContext(AppContext);
    const navigate = useNavigate();

    // Question Task States
    const [loadingChallenge, setLoadingChallenge] = useState(true);
    const [challenge, setChallenge] = useState<SystemChallenge | null>(null);
    const [selectedIndex, setSelectedIndex] = useState<number | null>(null);
    const [submittingChallenge, setSubmittingChallenge] = useState(false);

    // Social Task States
    const [xHandle, setXHandle] = useState("");
    const [verifyingSocial, setVerifyingSocial] = useState(false);
    const [showSocialInput, setShowSocialInput] = useState(false);

    // Global UI States
    const [showReward, setShowReward] = useState<{ amount: number; unit: string } | null>(null);
    const [timeLeft, setTimeLeft] = useState("");

    const today = new Date().toISOString().split('T')[0];
    const isAttemptedToday = user?.lastAiTaskDate === today;

    useEffect(() => {
        if (!isAttemptedToday) {
            generateSystemChallenge();
        } else {
            calculateTimeUntilNext();
            setLoadingChallenge(false);
        }
    }, [isAttemptedToday]);

    const calculateTimeUntilNext = () => {
        const now = new Date();
        const next = new Date();
        next.setHours(24, 0, 0, 0);
        const diff = next.getTime() - now.getTime();
        const hours = Math.floor(diff / (1000 * 60 * 60));
        const mins = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
        setTimeLeft(`${hours}h ${mins}m`);
    };

    const generateSystemChallenge = async () => {
        setLoadingChallenge(true);
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            // By including 'today' date string in the prompt, we ensure Gemini generates a consistent response for all users on that date
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: `Current Date: ${today}. As the protocol developer, generate a simple multiple-choice question about Web3 (blockchain, crypto, decentralization) or Trustrium project (www.trustrium.com). The question must be THE SAME every time for this specific date string. No AI or Assistant words. Options should be simple. Format: JSON {question, options[4], correctIndex}.`,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            question: { type: Type.STRING },
                            options: { 
                                type: Type.ARRAY, 
                                items: { type: Type.STRING },
                                minItems: 4,
                                maxItems: 4
                            },
                            correctIndex: { type: Type.INTEGER }
                        },
                        required: ["question", "options", "correctIndex"]
                    }
                }
            });

            if (response.text) {
                setChallenge(JSON.parse(response.text));
            }
        } catch (error) {
            console.error("System Error:", error);
            setChallenge({
                question: "What does $TSR stand for in our network?",
                options: ["Trust Token", "TSR Token", "The Shared Record", "Trustrium Standard"],
                correctIndex: 1
            });
        } finally {
            setLoadingChallenge(false);
        }
    };

    const handleChoice = (index: number) => {
        if (submittingChallenge || isAttemptedToday) return;
        setSelectedIndex(index);
    };

    const handleSubmitChallenge = async () => {
        if (selectedIndex === null || !challenge || submittingChallenge) return;

        setSubmittingChallenge(true);
        const isCorrect = selectedIndex === challenge.correctIndex;

        await submitAiTask(isCorrect);

        if (isCorrect) {
            setShowReward({ amount: 0.5, unit: "Trust" });
            showSuccessToast("Network Validation Success.");
        } else {
            showErrorToast("Validation failed. Try again tomorrow.");
        }
        setSubmittingChallenge(false);
    };

    const handleSocialTask = async () => {
        if (!xHandle || verifyingSocial) return;
        setVerifyingSocial(true);

        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            // Simulate AI check of the handle against follower list
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: `Analyze the X username "${xHandle}" and confirm if it follows the protocol's formatting standards for verification on x.com/trustrium. Provide a boolean 'verified' based on simulated API handshake.`,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: { verified: { type: Type.BOOLEAN } },
                        required: ["verified"]
                    }
                }
            });

            const result = JSON.parse(response.text);
            if (result.verified) {
                const success = await submitXFollowTask(xHandle);
                if (success) {
                    setShowReward({ amount: 0.5, unit: "Trust" });
                    showSuccessToast("Social verification complete!");
                }
            } else {
                showErrorToast("Verification failed. Please follow and try again.");
            }
        } catch (e) {
            showErrorToast("Verification link busy. Please try later.");
        } finally {
            setVerifyingSocial(false);
            setShowSocialInput(false);
        }
    };

    const HomePageLogo = ({ className }: { className?: string }) => (
        <img src="https://raw.githubusercontent.com/rashidali347/trsustrium001-logo/refs/heads/main/logo.png" alt="Trustrium Logo" className={className} />
    );

    return (
        <div className="container mx-auto max-w-lg flex flex-col min-h-screen font-sans bg-white dark:bg-brand-gray-950 transition-colors duration-300">
            {showReward && <RewardAnimation amount={showReward.amount} unit={showReward.unit} onAnimationEnd={() => setShowReward(null)} />}

            <header className="sticky top-0 z-[100] px-6 py-4 bg-white/90 dark:bg-brand-gray-950/90 backdrop-blur-xl border-b border-brand-gray-100 dark:border-brand-gray-800">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                        <HomePageLogo className="w-10 h-10 object-contain" />
                        <span className="font-black text-sm tracking-tight text-[#5839FF]">TRUSTRIUM</span>
                    </div>
                    <div className="bg-brand-gray-100 dark:bg-brand-gray-900 rounded-full p-1 flex items-center border border-brand-gray-200 dark:border-brand-gray-800">
                        <button onClick={() => navigate('/')} className="px-6 py-1.5 rounded-full text-xs font-bold transition-all text-brand-gray-400 hover:text-brand-gray-600 dark:hover:text-brand-gray-200">App</button>
                        <button onClick={() => navigate('/wallet')} className="px-6 py-1.5 rounded-full text-xs font-bold transition-all text-brand-gray-400 hover:text-brand-gray-600 dark:hover:text-brand-gray-200">Wallet</button>
                    </div>
                    <Link to="/profile">
                        <div className="w-10 h-10 rounded-full bg-brand-gray-100 dark:bg-brand-gray-900 border-2 border-white dark:border-brand-gray-800 shadow-xl overflow-hidden">
                            <img src={user?.avatar || `https://i.pravatar.cc/100?u=${user?.id}`} className="w-full h-full object-cover" alt="Profile" />
                        </div>
                    </Link>
                </div>
            </header>

            <div className="px-6 space-y-8 pt-6 pb-32">
                <div>
                    <h1 className="text-4xl font-bold text-brand-gray-900 dark:text-white tracking-tight">Tasks</h1>
                    <p className="text-brand-gray-400 font-medium text-sm">Earn daily Trust bonuses.</p>
                </div>

                {/* Section 1: Daily Protocol Check */}
                <div className="space-y-4">
                    <h3 className="text-xs font-black text-brand-gray-400 uppercase tracking-widest px-1">Daily System Challenge</h3>

                    {isAttemptedToday ? (
                        <div className="bg-brand-gray-50 dark:bg-brand-gray-900 rounded-[2.5rem] p-8 border border-brand-gray-100 dark:border-brand-gray-800 shadow-xl relative overflow-hidden">
                            <div className="flex flex-col items-center text-center space-y-4">
                                <div className={`w-16 h-16 rounded-full flex items-center justify-center ${user?.aiTaskCorrect ? 'bg-green-500' : 'bg-red-500'} text-white`}>
                                    {user?.aiTaskCorrect ? <ShieldCheck size={32} /> : <ShieldAlert size={32} />}
                                </div>
                                <div>
                                    <h4 className="text-xl font-bold text-brand-gray-900 dark:text-white">
                                        {user?.aiTaskCorrect ? 'Challenge Passed' : 'Try Again Tomorrow'}
                                    </h4>
                                    <p className="text-xs text-brand-gray-500 font-medium mt-1">Next protocol validation signature in:</p>
                                    <p className="text-lg font-black text-[#5839FF] mt-1">{timeLeft}</p>
                                </div>
                            </div>
                        </div>
                    ) : (
