                                <button 
                                    onClick={() => {
                                        window.open("https://x.com/trustrium", "_blank");
                                        setShowSocialInput(true);
                                    }}
                                    className="px-6 py-2.5 bg-[#5839FF] text-white font-black text-xs uppercase tracking-widest rounded-xl shadow-lg hover:brightness-110 active:scale-95 transition-all"
                                >
                                    Follow
                                </button>
                            )}
