                        {showSocialInput && !user?.xFollowed && (
                            <div className="mt-6 pt-6 border-t border-brand-gray-200 dark:border-brand-gray-800 space-y-4 animate-scale-in">
                                <div className="space-y-1">
                                    <label className="text-[10px] font-black text-brand-gray-400 uppercase tracking-widest ml-1">Enter your X Username</label>
                                    <div className="flex gap-2">
                                        <div className="relative flex-1">
                                            <span className="absolute left-4 top-3.5 text-brand-gray-400 font-bold">@</span>
                                            <input 
