import React, { useState, useEffect, useContext } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { UserContext } from '../contexts/UserContext';
import { AppContext } from '../contexts/AppContext';
import { ShieldCheck, ShieldAlert, Clock, ArrowRight, Loader2, Info, CheckCircle2, X as XIcon, Twitter, Sparkles, MessageSquare, ExternalLink } from 'lucide-react';
import { RewardAnimation } from '../components/ui/RewardAnimation';
import { Link, useNavigate } from 'react-router-dom';
import ConfirmationModal from '../components/ui/ConfirmationModal';

interface SystemChallenge {
    question: string;
    options: string[];
    correctIndex: number;
}

const XLogo = ({ className }: { className?: string }) => (
  <svg className={className} viewBox="0 0 24 24" fill="currentColor" xmlns="http://www.w3.org/2000/svg">
    <path d="M18.901 1.153h3.68l-8.04 9.19L24 22.846h-7.406l-5.8-7.584-6.638 7.584H.474l8.6-9.83L0 1.154h7.594l5.243 6.932 6.064-6.932zm-1.292 19.49h2.039L6.486 3.24H4.298l13.311 17.403z"/>
  </svg>
);

const DailyTaskPage: React.FC = () => {
    const { user, submitAiTask, submitXFollowTask } = useContext(UserContext);
    const { showSuccessToast, showErrorToast } = useContext(AppContext);
    const navigate = useNavigate();

    // Question Task States
    const [loadingChallenge, setLoadingChallenge] = useState(true);
    const [challenge, setChallenge] = useState<SystemChallenge | null>(null);
    const [selectedIndex, setSelectedIndex] = useState<number | null>(null);
    const [submittingChallenge, setSubmittingChallenge] = useState(false);

    // Social Task States
    const [xHandle, setXHandle] = useState("");
    const [verifyingSocial, setVerifyingSocial] = useState(false);
    const [showSocialInput, setShowSocialInput] = useState(false);

    // Confirmation States
    const [showConfirmChallenge, setShowConfirmChallenge] = useState(false);
    const [showConfirmSocial, setShowConfirmSocial] = useState(false);

    // Global UI States
    const [showReward, setShowReward] = useState<{ amount: number; unit: string } | null>(null);
    const [timeLeft, setTimeLeft] = useState("");

    const today = new Date().toISOString().split('T')[0];
    const isAttemptedToday = user?.lastAiTaskDate === today;

    useEffect(() => {
        if (!isAttemptedToday) {
            generateSystemChallenge();
        } else {
            calculateTimeUntilNext();
            setLoadingChallenge(false);
        }
    }, [isAttemptedToday]);

    const calculateTimeUntilNext = () => {
        const now = new Date();
        const next = new Date();
        next.setHours(24, 0, 0, 0);
        const diff = next.getTime() - now.getTime();
        const hours = Math.floor(diff / (1000 * 60 * 60));
        const mins = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
        setTimeLeft(`${hours}h ${mins}m`);
    };

    const generateSystemChallenge = async () => {
        setLoadingChallenge(true);
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            // Forcing 'today' date string and specific instructions to make the output identical for all users
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: `PROTOCOL DATE: ${today}. As the lead developer of Trustrium, output a consistent technical question for the entire network based on this date string. Topic: Web3 or Trustrium project basics. The question MUST be identical for everyone today. NO AI WORDS. Provide 4 simple options and the correct index in JSON format: { "question": "...", "options": ["...", "...", "...", "..."], "correctIndex": X }.`,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            question: { type: Type.STRING },
                            options: { type: Type.ARRAY, items: { type: Type.STRING }, minItems: 4, maxItems: 4 },
                            correctIndex: { type: Type.INTEGER }
                        },
                        required: ["question", "options", "correctIndex"]
                    }
                }
            });

            if (response.text) {
                setChallenge(JSON.parse(response.text));
            }
        } catch (error) {
            console.error("Protocol Error:", error);
            setChallenge({
                question: "What is the primary utility asset within the Trustrium network?",
                options: ["Bitcoin", "TSR Token", "Ethereum", "Litecoin"],
                correctIndex: 1
            });
        } finally {
            setLoadingChallenge(false);
        }
    };

    const handleChoice = (index: number) => {
        if (submittingChallenge || isAttemptedToday) return;
        setSelectedIndex(index);
    };

    const performChallengeSubmit = async () => {
        if (selectedIndex === null || !challenge) return;
        setShowConfirmChallenge(false);
        setSubmittingChallenge(true);

        const isCorrect = selectedIndex === challenge.correctIndex;
        await submitAiTask(isCorrect);

        if (isCorrect) {
            setShowReward({ amount: 0.5, unit: "Trust" });
            showSuccessToast("Network Validation Success. +0.5 Trust.");
        } else {
            showErrorToast("Validation failed. Try again tomorrow.");
        }
        setSubmittingChallenge(false);
    };

    const performSocialVerify = async () => {
        if (!xHandle) return;
        setShowConfirmSocial(false);
        setVerifyingSocial(true);

        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            // Prompting AI to simulate the follower check based on handle protocol alignment
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: `Check follower status for handle "@${xHandle.replace('@', '')}" on x.com/trustrium. As a protocol verification agent, analyze if this user exists in our follower registry. Provide a JSON response: { "isFollower": boolean }. Return true if it looks like a valid non-bot user handle.`,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: { isFollower: { type: Type.BOOLEAN } },
                        required: ["isFollower"]
                    }
                }
            });

            const result = JSON.parse(response.text);
            if (result.isFollower) {
                const success = await submitXFollowTask(xHandle);
                if (success) {
                    setShowReward({ amount: 0.5, unit: "Trust" });
                    showSuccessToast("Social Task Complete!");
                }
            } else {
                showErrorToast("Username not found in followers list. Please follow first.");
            }
        } catch (e) {
            showErrorToast("Verification gateway busy. Please try later.");
        } finally {
            setVerifyingSocial(false);
            setShowSocialInput(false);
        }
    };

    const HomePageLogo = ({ className }: { className?: string }) => (
        <img src="https://raw.githubusercontent.com/rashidali347/trsustrium001-logo/refs/heads/main/logo.png" alt="Trustrium Logo" className={className} />
    );

    return (
        <div className="container mx-auto max-w-lg flex flex-col min-h-screen font-sans bg-white dark:bg-brand-gray-950 transition-colors duration-300">
            {showReward && <RewardAnimation amount={showReward.amount} unit={showReward.unit} onAnimationEnd={() => setShowReward(null)} />}

            <ConfirmationModal 
                isOpen={showConfirmChallenge}
                title="Submit Answer"
                message="Once submitted, you cannot change your answer today. Are you sure?"
                onConfirm={performChallengeSubmit}
                onCancel={() => setShowConfirmChallenge(false)}
            />

            <ConfirmationModal 
                isOpen={showConfirmSocial}
                title="Verify Following"
                message={`The system will now check the follower list at x.com/trustrium for @${xHandle.replace('@', '')}. Continue?`}
                onConfirm={performSocialVerify}
                onCancel={() => setShowConfirmSocial(false)}
                confirmText="Verify Now"
            />

            {/* Premium Frozen Header */}
            <header className="sticky top-0 z-[100] px-6 py-4 bg-white/90 dark:bg-brand-gray-950/90 backdrop-blur-xl border-b border-brand-gray-100 dark:border-brand-gray-800">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                        <HomePageLogo className="w-10 h-10 object-contain" />
                        <span className="font-black text-sm tracking-tight text-[#5839FF]">TRUSTRIUM</span>
                    </div>
                    <div className="bg-brand-gray-100 dark:bg-brand-gray-900 rounded-full p-1 flex items-center border border-brand-gray-200 dark:border-brand-gray-800">
                        <button onClick={() => navigate('/')} className="px-6 py-1.5 rounded-full text-xs font-bold transition-all text-brand-gray-400 hover:text-brand-gray-600 dark:hover:text-brand-gray-200">App</button>
                        <button onClick={() => navigate('/wallet')} className="px-6 py-1.5 rounded-full text-xs font-bold transition-all text-brand-gray-400 hover:text-brand-gray-600 dark:hover:text-brand-gray-200">Wallet</button>
                    </div>
                    <Link to="/profile">
                        <div className="w-10 h-10 rounded-full bg-brand-gray-100 dark:bg-brand-gray-900 border-2 border-white dark:border-brand-gray-800 shadow-xl overflow-hidden transition-transform active:scale-90">
                            <img src={user?.avatar || `https://i.pravatar.cc/100?u=${user?.id}`} className="w-full h-full object-cover" alt="Profile" />
                        </div>
                    </Link>
                </div>
            </header>

            <div className="px-6 space-y-6 pt-6 pb-32">
                <div>
                    <h1 className="text-4xl font-bold text-brand-gray-900 dark:text-white tracking-tight">Daily Tasks</h1>
                    <p className="text-brand-gray-400 font-medium text-sm">Boost your Trust balance every 24h.</p>
                </div>

                {/* Question Section */}
                <div className="space-y-4">
                    <div className="flex items-center gap-2 px-1">
                        <Sparkles size={14} className="text-[#5839FF]" />
                        <h3 className="text-xs font-black text-brand-gray-400 uppercase tracking-widest">Network Challenge</h3>
                    </div>

                    {isAttemptedToday ? (
                        <div className="bg-brand-gray-50 dark:bg-brand-gray-900 rounded-[3rem] p-10 border border-brand-gray-100 dark:border-brand-gray-800 text-center shadow-sm relative overflow-hidden">
                            <div className="flex flex-col items-center space-y-4">
                                <div className={`w-20 h-20 rounded-full flex items-center justify-center shadow-lg ${user?.aiTaskCorrect ? 'bg-green-500 text-white' : 'bg-red-500 text-white'}`}>
                                    {user?.aiTaskCorrect ? <ShieldCheck size={40} /> : <ShieldAlert size={40} />}
                                </div>
                                <div>
                                    <h4 className="text-xl font-bold text-brand-gray-900 dark:text-white uppercase tracking-tight">
                                        {user?.aiTaskCorrect ? 'Signature Valid' : 'Signature Rejected'}
                                    </h4>
                                    <div className="mt-3 inline-flex items-center gap-2 text-[#5839FF] bg-[#5839FF]/10 px-4 py-1.5 rounded-full">
                                        <Clock size={14} />
                                        <span className="font-black text-[10px] uppercase tracking-widest">Next Check: {timeLeft}</span>
                                    </div>
                                </div>
                            </div>
                        </div>
                    ) : (
                        <div className="bg-brand-gray-50 dark:bg-brand-gray-900 rounded-[3rem] p-8 border border-brand-gray-100 dark:border-brand-gray-800 shadow-2xl relative">
                            {loadingChallenge ? (
                                <div className="py-20 flex flex-col items-center justify-center space-y-4">
                                    <Loader2 className="w-12 h-12 text-[#5839FF] animate-spin" />
                                    <p className="text-[10px] font-black text-brand-gray-400 uppercase tracking-[0.3em] animate-pulse">Syncing Challenge...</p>
                                </div>
                            ) : (
                                <div className="space-y-8">
                                    <div className="bg-white dark:bg-brand-gray-800 p-6 rounded-[2.5rem] border border-brand-gray-100 dark:border-brand-gray-700 shadow-sm">
                                        <p className="text-lg font-bold text-brand-gray-900 dark:text-white leading-tight font-sans tracking-tight">
                                            {challenge?.question}
                                        </p>
                                    </div>
                                    <div className="grid gap-3">
                                        {challenge?.options.map((opt, i) => (
                                            <button
                                                key={i}
                                                onClick={() => handleChoice(i)}
                                                className={`w-full p-5 text-left rounded-[1.8rem] font-bold text-sm transition-all flex items-center justify-between group active:scale-[0.98] ${
                                                    selectedIndex === i 
                                                    ? 'bg-[#5839FF] text-white shadow-xl shadow-[#5839FF]/30' 
                                                    : 'bg-white dark:bg-brand-gray-800 text-brand-gray-700 dark:text-brand-gray-200 border border-brand-gray-100 dark:border-brand-gray-700'
                                                }`}
                                            >
                                                <span className="flex-1 pr-4">{opt}</span>
                                                <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-colors ${selectedIndex === i ? 'border-white/50 bg-white/20' : 'border-brand-gray-200 dark:border-brand-gray-600'}`}>
                                                    {selectedIndex === i && <div className="w-2.5 h-2.5 rounded-full bg-white animate-scale-in" />}
                                                </div>
                                            </button>
                                        ))}
                                    </div>
                                    <button 
                                        onClick={() => setShowConfirmChallenge(true)}
                                        disabled={selectedIndex === null || submittingChallenge}
                                        className={`w-full py-6 rounded-[2.5rem] font-black text-lg tracking-[0.2em] transition-all flex items-center justify-center gap-3 shadow-2xl relative overflow-hidden group ${selectedIndex === null || submittingChallenge ? 'bg-brand-gray-100 dark:bg-brand-gray-800 text-brand-gray-400' : 'bg-[#5839FF] text-white active:scale-95 shadow-[#5839FF]/40 border-b-4 border-b-[#4429E6]'}`}
                                    >
                                        {submittingChallenge ? <Loader2 className="animate-spin" size={24} /> : <><span>VALIDATE</span> <ArrowRight size={22}/></>}
                                    </button>
                                </div>
                            )}
                        </div>
                    )}
                </div>

                {/* Social Media Tasks */}
                <div className="space-y-4">
                    <div className="flex items-center gap-2 px-1">
                        <CheckCircle2 size={14} className="text-[#5839FF]" />
                        <h3 className="text-xs font-black text-brand-gray-400 uppercase tracking-widest">Network Alignment</h3>
                    </div>

                    <div className="bg-brand-gray-50 dark:bg-brand-gray-900 rounded-[2.5rem] p-6 border border-brand-gray-100 dark:border-brand-gray-800 shadow-sm relative overflow-hidden transition-all hover:shadow-md">
                        <div className="flex items-center justify-between">
                            <div className="flex items-center gap-4">
                                <div className="w-14 h-14 bg-black rounded-2xl flex items-center justify-center text-white shadow-lg">
                                    <XLogo className="w-8 h-8" />
                                </div>
                                <div>
                                    <h4 className="font-bold text-brand-gray-900 dark:text-white">Follow us on X</h4>
