  const swapTrustToTSR = (trustAmount: number): { success: boolean; message: string; tsrReceived?: number } => {
    if (!user || trustAmount <= 0) return { success: false, message: 'Invalid amount.' };
    if (user.trustBalance < trustAmount) return { success: false, message: 'Insufficient Trust balance.' };

    const tsrReceived = trustAmount / 20;
    const newTrust = user.trustBalance - trustAmount;
    const newTsr = user.tsrBalance + tsrReceived;

    const newTx: Transaction = {
        id: `tx_${generateRandomHex(10)}`, trxId: `TSR-TX-${generateRandomHex(24).toUpperCase()}`,
        date: new Date().toISOString(), type: 'swap', amountTSR: tsrReceived, amountTrust: -trustAmount, status: 'completed'
    };

    const updatePayload: Partial<User> = { 
        trustBalance: newTrust, 
        tsrBalance: newTsr, 
        transactions: [newTx, ...user.transactions] 
    };

    if (isMining && user.miningSessionStartBalance !== undefined && user.miningSessionStartBalance !== null) {
      updatePayload.miningSessionStartBalance = user.miningSessionStartBalance - trustAmount;
    }

    updateUser(updatePayload);
    return { success: true, message: `Swapped ${trustAmount.toFixed(2)} Trust for ${tsrReceived.toFixed(4)} $TSR.`, tsrReceived };
